size(5cm);
draw((-1,0)--(5,0),EndArrow);
draw((0,-1)--(0,4),EndArrow);
label("$x$",(5,0),E);
label("$y$",(0,4),N);
for (int i=1; i<=4; ++i)
{
	draw((i,-.15)--(i,.15));
    if (i < 4)
    	draw((-.15,i)--(.15,i));
}
pair A=(0,0), B=(1,2), C=(3,3), D=(4,0);
draw(A--B--C--D--A);
draw((0,0)--(0,3)--(4,3)--(4,0)--cycle,dashed);
draw((0,2)--(1,2)--(1,3),dashed);
dot("$A$",A,SW);
dot("$B$",B,NW);
dot("$C$",C,N);
dot("$D$",D,S);
